#nullable enable // autogenerated

using System.Collections.Generic;
using System.Diagnostics.CodeAnalysis;
using MVZ2.GameContent.Entities;
using MVZ2.GameContent.Pickups;
using MVZ2.Vanilla.Audios;
using MVZ2.Vanilla.Entities;
using MVZ2.Vanilla.Grids;
using MVZ2.Vanilla.Properties;
using MVZ2Logic.Entities;
using PVZEngine;
using PVZEngine.Definitions;
using PVZEngine.Entities;
using PVZEngine.Level;
using PVZEngine.Modifiers;
using Tools;
using UnityEngine;

namespace MVZ2.GameContent.Contraptions
{
    [AutoEntityBehaviourDefinition(VanillaContraptionNames.netherReactorCore)]
    public class NetherReactorCore : AIEntityBehaviour
    {
        public NetherReactorCore(string nsp, string name) : base(nsp, name)
        {
            AddModifier(new FloatModifier(VanillaEntityProps.PRODUCE_SPEED, NumberOperator.Multiply, PROP_PRODUCE_SPEED_MULTIPLIER));
            AddModifier(new BooleanModifier(LogicEntityProps.IS_LIGHT_SOURCE, PROP_WORKING));
        }
        public override void Init(Entity entity)
        {
            base.Init(entity);
            SetProductionTimer(entity, TimerHelper.NewSecondTimer(MAX_PRODUCE_SECONDS));
        }
        protected override void UpdateAI(Entity entity)
        {
            base.UpdateAI(entity);
            if (entity.IsSecondsInterval(CHECK_INTERVAL_SECONDS))
            {
                Check(entity);
            }
            if (IsWorking(entity))
            {
                Work(entity);
            }
        }
        protected override void UpdateLogic(Entity entity)
        {
            base.UpdateLogic(entity);
            var productionTimer = GetProductionTimer(entity);
            entity.SetAnimationBool("Working", IsWorking(entity));
            entity.SetAnimationFloat("Progress", productionTimer?.GetPassedPercentage() ?? 0f);
        }

        private void Check(Entity entity)
        {
            var diagnoalID = CheckDiagnoalID(entity);
            var straightID = CheckStraightID(entity);
            if (IsValidPair(diagnoalID, straightID))
            {
                var multiplier = CalculateProduceSpeedMultiplier(entity.Level, diagnoalID, straightID);
                SetProduceSpeedMultiplier(entity, multiplier);
                if (!IsWorking(entity))
                {
                    entity.PlaySound(VanillaSoundID.ironCurtain);
                }
                SetWorking(entity, true);
            }
            else
            {
                SetProduceSpeedMultiplier(entity, 1);
                SetWorking(entity, false);
            }
        }
        private NamespaceID? CheckDiagnoalID(Entity entity)
        {
            return CheckID(entity, diagnoalOffsets);
        }
        private NamespaceID? CheckStraightID(Entity entity)
        {
            return CheckID(entity, straightOffsets);
        }
        private NamespaceID? CheckID(Entity entity, Vector2Int[] offsets)
        {
            var grid = entity.GetGrid();
            if (grid == null)
                return null;
            var level = entity.Level;
            var column = grid.Column;
            var lane = grid.Lane;
            const int count = 4;
            NamespaceID? entityID = null;
            var entityRefs = new HashSet<long>();
            for (int i = 0; i < count; i++)
            {
                var offset = offsets[i];
                var ent = level.GetGrid(column + offset.x, lane + offset.y)?.GetMainEntity();
                if (ent == null || entityRefs.Contains(ent.ID))
                    return null;
                var entID = ent.GetDefinitionID();
                if (entityID == null)
                {
                    entityID = entID;
                }
                else if (entID != entityID)
                {
                    return null;
                }
                entityRefs.Add(ent.ID);
            }
            return entityID;
        }
        private bool IsValidPair([NotNullWhen(true)] NamespaceID? id1, [NotNullWhen(true)] NamespaceID? id2)
        {
            if (id1 == null || id2 == null)
                return false;
            if (id1 == id2)
                return false;
            return true;
        }
        private float CalculateProduceSpeedMultiplier(LevelEngine level, NamespaceID id1, NamespaceID id2)
        {
            var def1 = level.Content.GetEntityDefinition(id1);
            if (def1 == null)
                return 1;
            var def2 = level.Content.GetEntityDefinition(id2);
            if (def2 == null)
                return 1;
            var rechargeID1 = def1.GetRechargeID();
            var recharge1 = level.Content.GetRechargeDefinition(rechargeID1);
            if (recharge1 == null)
                return 1;
            var rechargeID2 = def2.GetRechargeID();
            var recharge2 = level.Content.GetRechargeDefinition(rechargeID2);
            if (recharge2 == null)
                return 1;
            var cost1 = def1.GetCost();
            var cost2 = def2.GetCost();
            var t1 = cost1 * recharge1.GetQuality();
            var t2 = cost2 * recharge2.GetQuality();
            var t = (t1 + t2) / MAX_CONTRAPTION_QUALITY;
            return Mathf.Lerp(MIN_PRODUCE_SPEED_MULTIPLIER, MAX_PRODUCE_SPEED_MULTIPLIER, t);
        }
        private void Work(Entity entity)
        {
            var productionTimer = GetProductionTimer(entity);
            if (productionTimer.RunToExpiredAndNotNull(entity.GetProduceSpeed()))
            {
                productionTimer.Reset();
                entity.Spawn(VanillaPickupID.starshard, entity.GetCenter());
            }
        }
        public static FrameTimer? GetProductionTimer(Entity entity) => entity.GetProperty<FrameTimer>(PROP_PRODUCTION_TIMER);
        public static void SetProductionTimer(Entity entity, FrameTimer? timer) => entity.SetProperty(PROP_PRODUCTION_TIMER, timer);
        public static bool IsWorking(Entity entity) => entity.GetProperty<bool>(PROP_WORKING);
        public static void SetWorking(Entity entity, bool value) => entity.SetProperty(PROP_WORKING, value);
        public static float GetProduceSpeedMultiplier(Entity entity) => entity.GetProperty<float>(PROP_PRODUCE_SPEED_MULTIPLIER);
        public static void SetProduceSpeedMultiplier(Entity entity, float value) => entity.SetProperty(PROP_PRODUCE_SPEED_MULTIPLIER, value);

        private static readonly VanillaEntityPropertyMeta<FrameTimer> PROP_PRODUCTION_TIMER = new VanillaEntityPropertyMeta<FrameTimer>("production_timer");
        public static readonly VanillaEntityPropertyMeta<float> PROP_PRODUCE_SPEED_MULTIPLIER = new VanillaEntityPropertyMeta<float>("production_speed_multiplier", 1);
        public static readonly VanillaEntityPropertyMeta<bool> PROP_WORKING = new VanillaEntityPropertyMeta<bool>("working");

        public static readonly Vector2Int[] diagnoalOffsets = new Vector2Int[]
        {
            new Vector2Int(-1, -1),
            new Vector2Int(1, -1),
            new Vector2Int(-1, 1),
            new Vector2Int(1, 1),
        };
        public static readonly Vector2Int[] straightOffsets = new Vector2Int[]
        {
            new Vector2Int(-1, 0),
            new Vector2Int(0, -1),
            new Vector2Int(1, 0),
            new Vector2Int(0, 1),
        };
        public const float MAX_CONTRAPTION_QUALITY = 6000f;
        public const float MIN_PRODUCE_SPEED_MULTIPLIER = 1f;
        public const float MAX_PRODUCE_SPEED_MULTIPLIER = 10f;
        public const float MAX_PRODUCE_SECONDS = 300f;
        public const float CHECK_INTERVAL_SECONDS = 1f;
    }
}
